+    _ = qjs.JS_SetPropertyStr(ctx, util_obj, "inspect", qjs.JS_NewCFunction(ctx, utilInspect, "inspect", 1));
+    _ = qjs.JS_SetPropertyStr(ctx, util_obj, "promisify", qjs.JS_NewCFunction(ctx, utilPromisify, "promisify", 1));
